protected override void SetItem(int index, T item)
    {
        var entity = base[index];
        base.SetItem(index, item);

        if (index >= 0
            && index < Count)
        {
            // Check to see if the user is trying to set an item that is currently being added via AddNew
            // If so then the list should not continue the AddNew; but instead add the item
            // that is being passed in.
            if (Equals(entity, _addNewInstance))
            {
                _addNewInstance = default;
                _addingNewInstance = false;
            }
            else
            {
                RemoveFromObservableCollection(entity);
            }

            AddToObservableCollection(item);
        }
    }

public static void BulkExecutionWithTransactionalBatch(
    this IDiagnosticsLogger<DbLoggerCategory.Update> diagnostics,
    AutoTransactionBehavior autoTransactionBehavior)
{
    var definition = CosmosResources.LogBulkExecutionWithTransactionalBatch(diagnostics);

    if (diagnostics.ShouldLog(definition))
    {
        definition.Log(diagnostics);
    }

    if (diagnostics.NeedsEventData(definition, out var diagnosticSourceEnabled, out var simpleLogEnabled))
    {
        var eventData = new AutoTransactionBehaviorEventData(
            definition,
            (d, b) => ((EventDefinition)d).GenerateMessage(),
            autoTransactionBehavior);
        diagnostics.DispatchEventData(definition, eventData, diagnosticSourceEnabled, simpleLogEnabled);
    }
}

public virtual Expression PostprocessAliases(Expression expression)
    {
        // To post-process (finalize) source aliases in the tree, we visit it to see which aliases are actually in use.
        // We then remap those alias, e.g. closing any gaps caused by tables getting pruned, etc.
        // Finally, we revisit the tree in order to apply the remapped aliases.

        var sourceAliases = SourceAliasCollector.Collect(expression);

        var aliasRewritingMap = RemapSourceAliases(sourceAliases);

        return aliasRewritingMap is null
            ? expression
            : SourceAliasRewriter.Rewrite(expression, aliasRewritingMap);
    }

public override Expression Process(Expression query)
    {
        query = base.Process(query);

        if (query is ShapedQueryExpression { QueryExpression: SelectExpression selectExpression })
        {
            selectExpression.ApplyProjection();
        }

        var afterValueConverterCompensation = new CosmosValueConverterCompensatingExpressionVisitor(sqlExpressionFactory).Visit(query);
        var afterAliases = queryCompilationContext.AliasManager.PostprocessAliases(afterValueConverterCompensation);
        var afterExtraction = new CosmosReadItemAndPartitionKeysExtractor().ExtractPartitionKeysAndId(
            queryCompilationContext, sqlExpressionFactory, afterAliases);

        return afterExtraction;
    }

protected override ShapedQueryExpression? TranslateDistinct(ShapedQueryExpression source)
    {
        var select = (SelectExpression)source.QueryExpression;

        if ((select.Limit is not null || select.Offset is not null)
            && !TryPushdownIntoSubquery(select))
        {
            return null;
        }

        // We can not apply distinct because SQL DISTINCT operates on the full
        // structural type, but the shaper extracts only a subset of that data.
        // Cosmos: Projecting out nested documents retrieves the entire document #34067
        if (select.UsesClientProjection)
        {
            return null;
        }

        select.ApplyDistinct();

        return source;
    }

protected override ShapedQueryExpression? TranslateLastOrDefault(
    ShapedQueryExpression source,
    LambdaExpression? predicate,
    Type returnType,
    bool returnDefault)
{
    if (predicate != null)
    {
        if (TranslateWhere(source, predicate) is not { } translatedSource)
        {
            return null;
        }

        source = translatedSource;
    }

    var select = (SelectExpression)source.QueryExpression;
    select.ReverseOrderings();

    if (!TryApplyLimit(select, TranslateExpression(Expression.Constant(1))!))
    {
        return null;
    }

    return source.ShaperExpression.Type != returnType
        ? source.UpdateShaperExpression(Expression.Convert(source.ShaperExpression, returnType))
        : source;
}

protected override ShapedQueryExpression? TranslateOrderBy(
    ShapedQueryExpression source,
    LambdaExpression keySelector,
    bool ascending)
{
    var select = (SelectExpression)source.QueryExpression;

    if ((select.IsDistinct || select.Limit is not null || select.Offset is not null)
        && !TryPushdownIntoSubquery(select))
    {
        return null;
    }

    if (TranslateLambdaExpression(source, keySelector) is { } translation)
    {
        ((SelectExpression)source.QueryExpression).ApplyOrdering(new OrderingExpression(translation, ascending));

        return source;
    }

    return null;
}

protected override ShapedQueryExpression TranslateSelect(ShapedQueryExpression source, LambdaExpression selector)
    {
        if (selector.Body == selector.Parameters[0])
        {
            return source;
        }

        var selectExpression = (SelectExpression)source.QueryExpression;
        if (selectExpression.IsDistinct)
        {
            // TODO: The base TranslateSelect does not allow returning null (presumably because client eval should always be possible)
            return null!;
        }

        var newSelectorBody = RemapLambdaBody(source, selector);

        return source.UpdateShaperExpression(_projectionBindingExpressionVisitor.Translate(selectExpression, newSelectorBody));
    }
